// 雪花算法实现（41位时间戳 + 10位机器ID + 12位序列号）
- (NSString *)generateSnowflakeID {
    static uint64_t lastTimestamp = 0;
    static uint16_t sequence = 0;

    uint64_t currentTimestamp = (uint64_t)([[NSDate date] timeIntervalSince1970] * 1000);
    if (currentTimestamp < lastTimestamp) {
        currentTimestamp = lastTimestamp;   // 时钟回拨处理（极端情况）
    }

    if (currentTimestamp == lastTimestamp) {
        sequence = (sequence + 1) & 0xFFF; // 12位序列号（0-4095）
        if (sequence == 0) {
            // 当前毫秒序列号耗尽，等待下一毫秒
            while (currentTimestamp <= lastTimestamp) {
                currentTimestamp = (uint64_t)([[NSDate date] timeIntervalSince1970] * 1000);
            }
        }
    } else {
        sequence = 0;
    }

    lastTimestamp = currentTimestamp;

    // 合成ID（机器ID为设备UUID的hash）
    uint64_t machineID = [[[UIDevice currentDevice] identifierForVendor] hash] & 0x3FF; // 10位
    return [NSString stringWithFormat:@"%llu%llu%u", currentTimestamp, machineID, sequence];
}


@end

