- (void)handleAIResponse:(NSString *)content context:(NSString *)context {
    NSString *safeContent = content ?: @"";

    // 拼接内容到当前AI消息
    dispatch_async(dispatch_get_main_queue(), ^{
        if (self.currentAIMessage) {
            if ([self.currentAIMessage.content isEqualToString:@"思考中..."]) {
                self.currentAIMessage.content = @"";    // 移除初始占位文本
            }

