            // 刷新消息列表显示
            [self.messageListView updateMessage:self.currentAIMessage];
        }
    });
}

- (void)handleAIResponseEnd {
    dispatch_async(dispatch_get_main_queue(), ^{
        @try {
            if (self.currentAIMessage) {
                self.currentAIMessage.done = YES;
                [[WBStorageManager sharedManager] updateMessage:self.currentAIMessage]; // 最终更新消息
                [[WBStorageManager sharedManager] updateSessionLatestMessage:self.currentAIMessage.content forSessionId:self.sessionId];
