- (void)modifyAgentName {
    UIAlertController *alertController = [UIAlertController
                                          alertControllerWithTitle:@"对话名称"
                                          message:@""
                                          preferredStyle:UIAlertControllerStyleAlert];
    UIView *alertView = alertController.view.subviews.firstObject.subviews.firstObject.subviews.firstObject;
    alertView.backgroundColor = UIColor.whiteColor;

    __weak typeof(self) weakSelf = self;
    [alertController addTextFieldWithConfigurationHandler:^(UITextField *textField) {
        textField.placeholder = @"输入更改名称";
        textField.text = @"";
        textField.clearButtonMode = UITextFieldViewModeWhileEditing;
        // 文本变化监听
        [textField addTarget:weakSelf action:@selector(agentNameTextDidChange:) forControlEvents:UIControlEventEditingChanged];
    }];

    UIAlertAction *cancelAction = [UIAlertAction actionWithTitle:@"取消"
                                                          style:UIAlertActionStyleCancel
                                                        handler:nil];

    UIAlertAction *confirmAction = [UIAlertAction actionWithTitle:@"确定"
                                                           style:UIAlertActionStyleDefault
                                                         handler:^(UIAlertAction *action) {
        NSString *newName = alertController.textFields.firstObject.text;
        if (newName.length > 0) {
            weakSelf.agentName = newName;
            weakSelf.headerView.titleLabel.text = newName;
            [SVProgressHUD showSuccessWithStatus:@"修改成功"];
        } else {
            UIAlertController *alert = [UIAlertController
                                        alertControllerWithTitle:@"修改失败"
                                        message:@"名称不能为空"
                                        preferredStyle:UIAlertControllerStyleAlert];
            UIAlertAction *okAction = [UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleDefault handler:nil];
            [alert addAction:okAction];
            [self presentViewController:alert animated:YES completion:nil];
        }
    }];

    // 初始禁用确定按钮
    confirmAction.enabled = NO;
    [alertController addAction:cancelAction];
    [alertController addAction:confirmAction];

    [self presentViewController:alertController animated:YES completion:nil];
}

