- (void)hideIntroMask {
    if (!self.introMaskView) return;
    [UIView animateWithDuration:0.2 animations:^{
        self.introMaskView.alpha = 0;
    } completion:^(BOOL finished) {
        [self.introMaskView removeFromSuperview];
        [self.introMaskShapeLayer removeFromSuperlayer];
        self.introMaskView = nil;
        self.introMaskShapeLayer = nil;
        self.introMaskConfigured = NO;
        WBSettingManager.sharedManager.NotFirstTimePretense = YES;
    }];
}

- (void)updateIntroMaskWithHoleView1:(UIView *)maskHoleView1 hole2:(UIView *)maskHoleView2 {
    if (!self.introMaskView) return;
    [self.view layoutIfNeeded];
    CGRect bounds = self.view.bounds;
    UIBezierPath *path = [UIBezierPath bezierPathWithRect:bounds];
    CGRect holeRect1InView = [self.introMaskView convertRect:maskHoleView1.frame toView:self.view];
    [path appendPath:[UIBezierPath bezierPathWithRoundedRect:holeRect1InView cornerRadius:ZOOM(12)]];
    CGRect holeRect2InView = [self.introMaskView convertRect:maskHoleView2.frame toView:self.view];
    [path appendPath:[UIBezierPath bezierPathWithRoundedRect:holeRect2InView cornerRadius:ZOOM(12)]];
    if (!self.introMaskShapeLayer) {
        self.introMaskShapeLayer = [CAShapeLayer layer];
        self.introMaskShapeLayer.fillRule = kCAFillRuleEvenOdd;
        self.introMaskShapeLayer.fillColor = [UIColor colorWithWhite:0 alpha:0.4].CGColor;
        [self.introMaskView.layer addSublayer:self.introMaskShapeLayer];
    }
    self.introMaskShapeLayer.frame = bounds;
    self.introMaskShapeLayer.path = path.CGPath;
}

- (void)updateIntroMaskHoles {
    if (!self.introMaskView) return;
    NSArray<UIView *> *subviews = self.introMaskView.subviews;
    if (subviews.count < 2) return;
    UIView *hole1 = subviews.firstObject;
    UIView *hole2 = subviews[1];
    [self updateIntroMaskWithHoleView1:hole1 hole2:hole2];
}


